use actix_web::{get, web, HttpResponse};
use sqlx::SqlitePool;

#[get("/invoices/{id}")]
async fn get_invoice(id: web::Path<String>, db: SqlitePool) -> Result<HttpResponse> {
    let user = web::Data::<User>::from(&req);

    // Extract the ID from the URL path and query the database
    let invoice = db.query_one("SELECT * FROM invoices WHERE id = ? AND user_id = ?", &[id, user.id]).await?;

    Ok(HttpResponse::Ok().json(invoice))
}